var createCarnival=function(e,t="carnival-script"){let c=document.querySelector(e);c||(c=document.body);const r=document.createElement("script");return r.id=t,r.src="https://www.eveningwater.com/static/plugin/carnival.min.js",document.querySelector(t)||c.appendChild(r),{destory(){r.remove(),document.body.style.cssText="",[...document.querySelectorAll(".mw_added_css")].forEach((e=>e.remove()))}}};